select lv.id, lv.listing_id, lv.description, lv.price_cents, lv.currency, lv.max_submissions, lv.sample_videos, lv.created_at
from public.listing_versions lv
order by lv.created_at desc;

select lc.id, lc.listing_version_id, lc.kind, lc.metric, lc.platform, lc.operator, lc.value_numeric, lc.value_bool, lc.description
from public.listing_conditions lc
order by lc.listing_version_id, lc.kind, lc.metric;

select lv.id, lv.listing_id, lv.version_number, lv.price_cents, lv.currency, lv.max_submissions, lv.snapshot->>'description' as description, lv.snapshot->'sample_videos' as sample_videos
from public.listing_versions lv
order by lv.created_at desc;

select id, listing_version_id, kind, metric, platform, operator, numeric_value, bool_value, description
from public.listing_conditions
order by listing_version_id, kind;

select id, listing_version_id, kind, metric::text as metric, platform::text as platform, operator, numeric_threshold, bool_threshold
from public.listing_conditions
order by listing_version_id, kind, metric::text;

