1	// Edge function: get-listing-detail (US-039)
2	//
3	// Contract:
4	//   POST { listing_id: string }
5	//     → 200 {
6	//         listing:          <row from public.listings>,
7	//         conditions:       <rows from listing_conditions, both kinds>,
8	//         sample_videos:    <rows from sample_videos>,
9	//         eligibility: {
10	//           eligible:                boolean,
11	//           failed_conditions:       Array<{metric, platform, required, actual}>,
12	//           has_active_application:  boolean,
13	//         }
14	//       }
15	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
16	//     → 401 { error: 'UNAUTHORIZED' }
17	//     → 403 { error: 'FORBIDDEN' }       // non-creator role
18	//     → 404 { error: 'LISTING_NOT_FOUND' } // also covers draft/archived listings
19	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
20	//
21	// Auth: Marketify JWT (HS256, MARKETIFY_JWT_SECRET). Verifies via
22	//       _shared/jwt.ts and asserts role='creator'. Deployed with
23	//       verify_jwt=false at the gateway because the gateway only knows
24	//       about Supabase's own JWT secret — the handler enforces auth.
25	//
26	// Response shape — primary reference is docs/tech-architecture.md §5.4
27	// (spec is authoritative per the Ralph iteration rules). Two deltas vs
28	// the US-039 story AC, both driven by §5.4:
29	//   1. `conditions` is a single array — the client splits by `kind`.
30	//      The story's `pre_conditions` / `post_conditions` split contradicts
31	//      §5.4's single `conditions: ListingCondition[]` field.
32	//   2. `eligibility.failed_conditions` is `Array<{metric, required, actual}>`
33	//      — the story's `reasons: string[]` contradicts §5.4. We also keep
34	//      `platform` as an additive disambiguator because `min_followers`
35	//      would otherwise be ambiguous across TikTok/Instagram; §5.4 is
36	//      under-specified on the item shape and an additive field is not
37	//      a structural departure.
38	//
39	// Eligibility — only PRE conditions gate apply-time eligibility per
40	// docs/tech-architecture.md §6.3 ("Pre-conditions: evaluated on all
41	// posts; post-conditions: evaluated on submissions"). POST conditions
42	// are returned in `conditions` for the UI to display but do not
43	// contribute to `eligible` / `failed_conditions`.
44	//
45	// Fail-closed on missing metrics (§3d): when the creator hasn't been
46	// scraped yet (or a specific platform field is NULL), the PRE condition
47	// keyed on that field fails — the spec calls this out explicitly for
48	// Instagram `min_avg_views_last_n` ("Listings that require … treat null
49	// as ineligible (fail-closed).") and we apply the same rule uniformly.
50	// The same rule extends to pre-condition rows with an unknown operator
51	// or unreadable metric: treat as failed rather than silently passing,
52	// so a future mis-migrated row can't flip a listing to eligible by
53	// accident.
54	//
55	// Visibility — a creator lookup against a `draft` or `archived` listing
56	// collapses to 404. Draft is never public; archived is terminal and no
57	// application path can succeed against it, so leaking its existence
58	// would only produce a dead-end detail view. `paused` and `closed` still
59	// return 200 so a creator with an existing application can view the
60	// detail; the Apply CTA in US-040 gates off `listing.status`.
61	
62	import { createClient } from "npm:@supabase/supabase-js@2";
63	import { verifyJwt } from "../_shared/jwt.ts";
64	import { corsHeaders } from "../_shared/cors.ts";
65	
66	const UUID_RE =
67	  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
68	
69	type Platform = "tiktok" | "instagram";
70	type ConditionKind = "pre" | "post";
71	
72	interface ConditionRow {
73	  id: string;
74	  listing_version_id: string;
75	  kind: ConditionKind;
76	  metric: string;
77	  platform: Platform | null;
78	  operator: string;
79	  numeric_threshold: string | number | null;
80	  text_threshold: string | null;
81	  bool_threshold: boolean | null;
82	  created_at: string;
83	}
84	
85	interface CreatorProfileRow {
86	  tiktok_follower_count: number | null;
87	  tiktok_avg_views_last_10: number | null;
88	  tiktok_total_likes: number | null;
89	  tiktok_video_count: number | null;
90	  tiktok_is_verified: boolean | null;
91	  instagram_follower_count: number | null;
92	  instagram_avg_views_last_10: number | null;
93	  instagram_media_count: number | null;
94	}
95	
96	interface FailedCondition {
97	  metric: string;
98	  platform: Platform | null;
99	  required: number | boolean;
100	  actual: number | boolean | null;
101	}
102	
103	interface DetailRequest {
104	  listing_id?: unknown;
105	}
106	
107	function jsonResponse(status: number, body: unknown): Response {
108	  return new Response(JSON.stringify(body), {
109	    status,
110	    headers: { ...corsHeaders, "Content-Type": "application/json" },
111	  });
112	}
113	
114	function bearerToken(req: Request): string | null {
115	  const raw = req.headers.get("Authorization") ??
116	    req.headers.get("authorization");
117	  if (!raw) return null;
118	  const m = raw.match(/^Bearer\s+(.+)$/i);
119	  return m ? m[1].trim() : null;
120	}
121	
122	// Evaluate a single pre-condition against the creator's denormalized
123	// metrics. Returns `null` on pass, or the failed-condition detail on fail.
124	// Missing data (null actual for a numeric threshold) fails closed per §3d.
125	function evaluatePreCondition(
126	  condition: ConditionRow,
127	  metrics: CreatorProfileRow,
128	): FailedCondition | null {
129	  const { metric, platform, operator } = condition;
130	  if (operator === "gte") {
131	    const required = Number(condition.numeric_threshold);
132	    if (!Number.isFinite(required)) return null; // malformed row — skip, not fail
133	    const actual = readNumericMetric(metrics, platform, metric);
134	    if (actual === null || actual < required) {
135	      return { metric, platform, required, actual };
136	    }
137	    return null;
138	  }
139	  if (operator === "bool") {
140	    const required = condition.bool_threshold === true;
141	    const actual = readBoolMetric(metrics, platform, metric);
142	    if (actual !== required) {
143	      return { metric, platform, required, actual };
144	    }
145	    return null;
146	  }
147	  // Unknown operator on a PRE row — fail-closed per §3d. `eq`/`contains`/`lte`
148	  // are reserved for post-conditions today (e.g. post_must_mention uses
149	  // 'contains'), so this branch should be unreachable; if a future migration
150	  // misplaces an operator, we'd rather block an apply than silently allow it.
151	  console.warn("pre-condition with unknown operator treated as failed", {
152	    condition_id: condition.id,
153	    operator,
154	    metric,
155	    platform,
156	  });
157	  const parsed = Number(condition.numeric_threshold);
158	  return {
159	    metric,
160	    platform,
161	    required: Number.isFinite(parsed) ? parsed : 0,
162	    actual: null,
163	  };
164	}
165	
166	function readNumericMetric(
167	  metrics: CreatorProfileRow,
168	  platform: Platform | null,
169	  metric: string,
170	): number | null {
171	  if (platform === "tiktok") {
172	    switch (metric) {
173	      case "min_followers":
174	        return metrics.tiktok_follower_count;
175	      case "min_avg_views_last_n":
176	        return metrics.tiktok_avg_views_last_10;
177	      case "min_total_likes":
178	        return metrics.tiktok_total_likes;
179	      case "min_videos_posted":
180	        return metrics.tiktok_video_count;
181	      default:
182	        return null;
183	    }
184	  }
185	  if (platform === "instagram") {
186	    switch (metric) {
187	      case "min_followers":
188	        return metrics.instagram_follower_count;
189	      case "min_avg_views_last_n":
190	        return metrics.instagram_avg_views_last_10;
191	      case "min_videos_posted":
192	        return metrics.instagram_media_count;
193	      default:
194	        return null;
195	    }
196	  }
197	  return null;
198	}
199	
200	function readBoolMetric(
201	  metrics: CreatorProfileRow,
202	  platform: Platform | null,
203	  metric: string,
204	): boolean | null {
205	  if (platform === "tiktok" && metric === "verified_only") {
206	    return metrics.tiktok_is_verified;
207	  }
208	  return null;
209	}
210	
211	Deno.serve(async (req) => {
212	  if (req.method === "OPTIONS") {
213	    return new Response(null, { status: 204, headers: corsHeaders });
214	  }
215	  if (req.method !== "POST") {
216	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
217	  }
218	
219	  const token = bearerToken(req);
220	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
221	
222	  let claims;
223	  try {
224	    claims = await verifyJwt(token);
225	  } catch {
226	    return jsonResponse(401, { error: "UNAUTHORIZED" });
227	  }
228	  if (claims.role !== "creator") {
229	    return jsonResponse(403, { error: "FORBIDDEN" });
230	  }
231	
232	  let body: DetailRequest;
233	  try {
234	    body = await req.json();
235	  } catch {
236	    return jsonResponse(400, { error: "INVALID_JSON" });
237	  }
238	
239	  const listingId =
240	    typeof body.listing_id === "string" && UUID_RE.test(body.listing_id)
241	      ? body.listing_id
242	      : null;
243	  if (!listingId) {
244	    return jsonResponse(400, { error: "INVALID_REQUEST" });
245	  }
246	
247	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
248	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
249	  if (!supabaseUrl || !serviceRoleKey) {
250	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
251	  }
252	
253	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
254	    auth: { persistSession: false, autoRefreshToken: false },
255	  });
256	
257	  const { data: listing, error: listingError } = await supabase
258	    .from("listings")
259	    .select("*")
260	    .eq("id", listingId)
261	    .maybeSingle();
