import { useCallback, useEffect, useState } from 'react';
import {
  ActivityIndicator,
  SafeAreaView,
  ScrollView,
  StyleSheet,
  Text,
  View,
} from 'react-native';
import { ButtonSecondary } from '@/components/primitives/Button';
import { useToast } from '@/components/primitives/Toast';
import { colors, radii, shadows, spacing } from '@/design/tokens';
import { textStyles } from '@/design/typography';
import { useAuth } from '@/lib/auth';
import { supabase } from '@/lib/supabase';
import type { Database } from '@/types/supabase';

// US-037 — lister profile. Renders org_name (from lister_profiles),
// email + username (from users via AuthContext), and a canonical sign-out
// button. Sign-out clears the persisted JWT via AuthProvider.signOut,
// which triggers the role-based router at app/index.tsx to drop the user
// back into the (auth) group.

type ListerProfileRow = Database['public']['Tables']['lister_profiles']['Row'];

export default function ListerProfile() {
  const { user, signOut } = useAuth();
  const { show: showToast } = useToast();

  const [profile, setProfile] = useState<ListerProfileRow | null>(null);
  const [loading, setLoading] = useState(true);

  const load = useCallback(async () => {
    if (!user) return;
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('lister_profiles')
        .select('*')
        .eq('user_id', user.id)
        .maybeSingle();
      if (error) throw error;
      setProfile(data ?? null);
    } catch (err) {
      console.error('Lister profile load failed', err);
      showToast({ message: 'Could not load profile.', variant: 'error' });
    } finally {
      setLoading(false);
    }
  }, [user, showToast]);

  useEffect(() => {
    void load();
  }, [load]);

  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.scrollContent}>
        <View style={styles.header}>
          <Text style={[textStyles.display, { color: colors.ink }]}>Profile</Text>
          {user ? (
            <Text style={[textStyles.mono, styles.usernameRow]}>@{user.username}</Text>
          ) : null}
        </View>

        {loading && profile === null ? (
          <View style={styles.loadingBlock}>
            <ActivityIndicator color={colors.ink} />
          </View>
        ) : (
          <View style={styles.card} testID="lister-company-card">
            <Text style={[textStyles.h2, { color: colors.ink }]}>Company</Text>
            <DetailRow label="Organization" value={profile?.org_name ?? null} />
            <DetailRow label="Email" value={user?.email ?? null} />
          </View>
        )}

        <View style={styles.signOutWrap}>
          <ButtonSecondary
            label="Sign out"

// Typography — typed text-style presets for the Marketify design system.
// Mirrors docs/design.md §1.3 (font pairing table + line-height rules).
//
// Font substitution: docs/design.md names Clash Display (headings) and Satoshi (body).
// Both are Fontshare-hosted and do not ship with Expo Google Fonts; we use the explicit
// fallbacks listed in §1.3 — Outfit for display/headings, Rubik for body/caption — plus
// JetBrains Mono for monospace. Spec-sanctioned per the same section.
//
// `fontFamily` values are the string keys registered with `expo-font.useFonts` in
// `app/_layout.tsx`. They MUST match the constant names imported from
// `@expo-google-fonts/*` so RN can resolve the loaded assets by name.

import {
  Outfit_600SemiBold,
  Outfit_700Bold,
} from '@expo-google-fonts/outfit';
import {
  Rubik_500Medium,
  Rubik_700Bold,
} from '@expo-google-fonts/rubik';
import { JetBrainsMono_500Medium } from '@expo-google-fonts/jetbrains-mono';
import type { TextStyle } from 'react-native';

export const fontFamilies = {
  displayBold: 'Outfit_700Bold',
  displaySemi: 'Outfit_600SemiBold',
  bodyMedium: 'Rubik_500Medium',
  bodyBold: 'Rubik_700Bold',
  mono: 'JetBrainsMono_500Medium',
} as const;

// Map consumed by `useFonts` — values are the numeric asset handles exported by
// @expo-google-fonts/*, keys are the runtime font-family names.
export const fontAssets = {
  [fontFamilies.displayBold]: Outfit_700Bold,
  [fontFamilies.displaySemi]: Outfit_600SemiBold,
  [fontFamilies.bodyMedium]: Rubik_500Medium,
  [fontFamilies.bodyBold]: Rubik_700Bold,
  [fontFamilies.mono]: JetBrainsMono_500Medium,
} as const;

// Line heights per §1.3: 1.15 for display, ~1.55 for body. Caption + mono tighten
// to 1.4 for dense data rows.
export const textStyles = {
  display: {
    fontFamily: fontFamilies.displayBold,
    fontSize: 28,
    lineHeight: 32,
  },
  h1: {
    fontFamily: fontFamilies.displaySemi,
    fontSize: 22,
    lineHeight: 25,
  },
  h2: {
    fontFamily: fontFamilies.displaySemi,
    fontSize: 20,
    lineHeight: 23,
  },
  body: {
    fontFamily: fontFamilies.bodyMedium,
    fontSize: 15,
    lineHeight: 23,
  },
  caption: {
    fontFamily: fontFamilies.bodyMedium,
    fontSize: 13,
    lineHeight: 18,
  },
  mono: {
    fontFamily: fontFamilies.mono,
    fontSize: 14,
    lineHeight: 20,
  },
  // Micro (pills + chip labels) per §1.3 — Rubik_700Bold stands in for Satoshi 700,
  // 0.08em tracking at 11pt = 0.88pt (RN letterSpacing is absolute points).
  micro: {
    fontFamily: fontFamilies.bodyBold,
    fontSize: 11,
    lineHeight: 14,
    letterSpacing: 0.88,
    textTransform: 'uppercase',
  },
} as const satisfies Record<string, TextStyle>;

export type TextStyleToken = keyof typeof textStyles;
export type FontFamilyToken = keyof typeof fontFamilies;

export type Json =
  | string
  | number
  | boolean
  | null
  | { [key: string]: Json | undefined }
  | Json[]

