421	function EligibilityRow({
422	  condition,
423	  failure,
424	}: {
425	  condition: ConditionRow;
426	  failure: FailedCondition | null;
427	}) {
428	  const passed = failure === null;
429	  const label = eligibilityRowLabel(condition);
430	  const statusColor = passed ? colors.success : colors.danger;
431	  const Icon = passed ? Check : X;
432	  const detail = passed
433	    ? requiredLabel(condition)
434	    : failureDetailLabel(condition, failure);
435	  return (
436	    <View
437	      style={styles.eligibilityRow}
438	      accessible
439	      accessibilityLabel={
440	        passed
441	          ? `${label} passes. Required ${requiredLabel(condition)}.`
442	          : `${label} fails. ${detail}.`
443	      }
444	      testID={`listing-eligibility-${condition.metric}-${condition.platform ?? 'none'}`}
445	    >
446	      <View style={[styles.eligibilityIcon, { borderColor: statusColor }]}>
447	        <Icon color={statusColor} size={16} strokeWidth={3} />
448	      </View>
449	      <View style={styles.eligibilityTextWrap}>
450	        <Text style={[textStyles.body, { color: colors.ink }]}>{label}</Text>
451	        <Text style={[textStyles.caption, { color: colors.ink70 }]}>{detail}</Text>
452	      </View>
453	    </View>
454	  );
