473	  switch (status) {
474	    case 'paused':
475	      return 'This campaign is paused. The lister is reviewing pending applications.';
476	    case 'closed':
477	      return 'This campaign is closed and no longer accepting applications.';
478	    default:
479	      return null;
480	  }
481	}
