484	  const platform = c.platform ? platformLabel(c.platform) : '';
485	  const base = metricLabel(c.metric);
486	  return platform ? `${platform} · ${base}` : base;
487	}
488	
489	function metricLabel(metric: string): string {
490	  switch (metric) {
491	    case 'min_followers':
492	      return 'Minimum followers';
493	    case 'min_avg_views_last_n':
494	      return 'Avg views (last 10)';
495	    case 'min_total_likes':
496	      return 'Total likes';
497	    case 'min_videos_posted':
498	      return 'Videos posted';
499	    case 'verified_only':
500	      return 'Verified account';
501	    default:
502	      return metric;
503	  }
504	}
505	
506	function requiredLabel(c: ConditionRow): string {
507	  if (c.operator === 'bool') {
508	    return `Requires ${c.bool_threshold ? 'yes' : 'no'}`;
509	  }
510	  const threshold = c.numeric_threshold;
511	  if (threshold !== null && threshold !== undefined) {
512	    return `Requires ${formatCount(Number(threshold))}+`;
513	  }
514	  return '—';
515	}
516	
517	function failureDetailLabel(
518	  c: ConditionRow,
519	  f: FailedCondition,
520	): string {
521	  const required = requiredLabel(c);
522	  if (typeof f.actual === 'number') {
523	    return `${required} — you have ${formatCount(f.actual)}`;
524	  }
525	  if (typeof f.actual === 'boolean') {
526	    return `${required} — you are ${f.actual ? 'verified' : 'not verified'}`;
527	  }
528	  return `${required} — no data yet`;
529	}
530	
531	function postConditionLabel(c: ConditionRow): string {
532	  switch (c.metric) {
533	    case 'post_family_friendly':
534	      return c.bool_threshold ? 'Family-friendly content only.' : 'Content may be mature.';
535	    case 'post_must_mention':
536	      return c.text_threshold
537	        ? `Must mention ${c.text_threshold}.`
538	        : 'Must include a specific mention.';
539	    case 'post_must_tag_account':
540	      return c.text_threshold
541	        ? `Must tag @${c.text_threshold.replace(/^@/, '')}.`
542	        : 'Must tag the lister account.';
543	    case 'post_min_video_duration_sec':
544	      return c.numeric_threshold !== null
545	        ? `Video at least ${c.numeric_threshold}s.`
546	        : 'Minimum video duration.';
547	    case 'post_max_video_duration_sec':
548	      return c.numeric_threshold !== null
549	        ? `Video at most ${c.numeric_threshold}s.`
550	        : 'Maximum video duration.';
551	    case 'post_min_video_count':
552	      return c.numeric_threshold !== null
553	        ? `Post at least ${c.numeric_threshold} videos.`
554	        : 'Minimum video count.';
555	    default:
556	      return c.metric;
557	  }
558	}
559	
560	function platformLabel(p: Platform): string {
561	  return p === 'tiktok' ? 'TikTok' : 'Instagram';
562	}
563	
564	function formatPrice(priceCents: number, currency: string): string {
565	  const amount = (priceCents / 100).toLocaleString('en-US', {
566	    minimumFractionDigits: 0,
567	    maximumFractionDigits: 2,
568	  });
569	  const code = currency.toUpperCase();
570	  if (code === 'USD') return `$${amount}`;
571	  return `${amount} ${code}`;
572	}
573	
574	function formatCount(n: number): string {
575	  if (n < 1000) return String(n);
576	  if (n < 1_000_000) return `${(n / 1000).toFixed(n < 10_000 ? 1 : 0)}k`;
577	  if (n < 1_000_000_000) return `${(n / 1_000_000).toFixed(n < 10_000_000 ? 1 : 0)}m`;
578	  return `${(n / 1_000_000_000).toFixed(n < 10_000_000_000 ? 1 : 0)}b`;
579	}
580	
